import React from "react";

function Sidebar({ active, onMenuClick }) {
  const menu = [
    { key: "dashboard", label: "Dashboard", icon: "🏠" },
    { key: "agendar", label: "Agendar Paciente", icon: "📅" },
    { key: "agendamentos", label: "Agendamentos", icon: "🗂️" },
    { key: "disciplinas", label: "Disciplinas", icon: "📚" },
    { key: "pacientes", label: "Pacientes", icon: "🧑‍⚕️" },
    { key: "alunos", label: "Alunos", icon: "🎓" },
    { key: "solicitacoes", label: "Solicitações", icon: "📬" },
  ];

  return (
    <aside className="w-64 bg-white border-r border-gray-200 shadow-lg rounded-r-2xl flex flex-col items-center py-8 min-h-screen">
      {/* Logo */}
      <div className="mb-12 flex items-center justify-center w-full">
        <div className="bg-blue-600 text-white rounded-full h-16 w-16 flex items-center justify-center text-3xl font-bold shadow-md">
          PoliUb Agendamentos
        </div>
      </div>

      {/* Menu */}
      <nav className="flex flex-col gap-3 w-full px-4">
        {menu.map((item) => (
          <button
            key={item.key}
            onClick={() => onMenuClick(item.key)}
            className={`flex items-center gap-3 px-4 py-3 rounded-xl text-lg font-medium transition-colors
              ${
                active === item.key
                  ? "bg-blue-100 text-blue-700 shadow-sm"
                  : "text-gray-700 hover:bg-gray-100"
              }`}
          >
            <span className="text-2xl">{item.icon}</span>
            {item.label}
          </button>
        ))}
      </nav>

      {/* Footer */}
      <div className="mt-auto w-full px-4">
        <button className="flex items-center gap-2 px-4 py-2 rounded-xl w-full text-gray-500 hover:bg-gray-50 mt-6">
          ⚙️ Configurações
        </button>
        <button className="flex items-center gap-2 px-4 py-2 rounded-xl w-full text-gray-500 hover:bg-gray-50">
          ❓ Ajuda
        </button>
      </div>
    </aside>
  );
}

export default Sidebar;
